// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// A deep copy of each item is passed to the script to avoid mutation of the original data.
// Each script execution is limited to a maximum runtime (500ms) to mitigate denial‑of‑service attacks.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	// Maximum allowed execution time for a single script.
	const scriptTimeout = 500 * time.Millisecond

	for _, item := range items {
		// Create a new VM for each item to ensure isolation.
		vm := otto.New()

		// Deep copy the current item so the script cannot modify the original slice.
		itemCopy, err := deepCopyMap(item)
		if err != nil {
			return nil, fmt.Errorf("failed to copy item: %w", err)
		}

		// Inject the copied item into the JavaScript environment.
		if err := vm.Set("item", itemCopy); err != nil {
			return nil, err
		}

		// Set up a timeout to abort long‑running scripts.
		timer := time.AfterFunc(scriptTimeout, func() {
			vm.Interrupt <- func() {}
		})

		// Run the script.
		val, err := vm.Run(conditionScript)

		// Stop the timer; if it already fired this is a no‑op.
		if !timer.Stop() {
			// The timer fired, meaning the script was interrupted.
			return nil, fmt.Errorf("script execution timed out")
		}
		if err != nil {
			return nil, fmt.Errorf("script error: %w", err)
		}

		// Convert the JavaScript result to a Go boolean using JavaScript truthiness.
		ok, err := val.ToBoolean()
		if err != nil {
			return nil, err
		}

		if ok {
			// Append the original (unmodified) item to the result.
			result = append(result, item)
		}
	}

	return result, nil
}

// deepCopyMap creates a deep copy of a map[string]interface{} using JSON marshaling.
func deepCopyMap(m map[string]interface{}) (map[string]interface{}, error) {
	data, err := json.Marshal(m)
	if err != nil {
