)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
// A timeout is applied to each script execution to prevent infinite loops.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	for _, item := range items {
		// Create a new VM for each item to ensure complete isolation between executions
		// This prevents any state pollution from previous iterations
		vm := otto.New()

		// Inject the current item as a global variable named 'item'
		err := vm.Set("item", item)
		if err != nil {
			return nil, err
		}

		// Use context with timeout to prevent infinite loops in the script
		ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
		defer cancel()

		// Create a channel to receive the result from the goroutine
		type scriptResult struct {
			value otto.Value
			err   error
		}
		resultChan := make(chan scriptResult, 1)

		// Run the script in a separate goroutine so we can apply timeout
		go func() {
			value, err := vm.Run(conditionScript)
			resultChan <- scriptResult{value, err}
		}()

		// Wait for either the script to complete or timeout
		select {
		case res := <-resultChan:
			if res.err != nil {
				return nil, res.err
			}

			// Convert result to boolean using JavaScript truthiness
			boolResult, err := res.value.ToBoolean()
			if err != nil {
				return nil, err
			}

			if boolResult {
				result = append(result, item)
			}
		case <-ctx.Done():
			return nil, ctx.Err()
		}
	}

	return result, nil
}

