// FilterItems executes a JavaScript condition script for each item in the slice.
// The script has access to a global variable named `item` which contains the current map.
// Only the items for which the script evaluates to true (or a truthy value) are returned.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var filtered []map[string]interface{}

	for _, item := range items {
		// Create a fresh VM for each iteration to avoid state leakage
		vm := otto.New()

		// Inject the current item into the VM as a global variable named "item"
		if err := vm.Set("item", item); err != nil {
			return nil, fmt.Errorf("failed to set item: %w", err)
		}

		// Run the condition script
		val, err := vm.Run(conditionScript)
		if err != nil {
			return nil, fmt.Errorf("script execution error for item: %w", err)
		}

		// Convert the result to a boolean value
		match, err := val.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("failed to convert script result to boolean: %w", err)
		}

		if match {
			filtered = append(filtered, item)
		}
	}

	return filtered, nil
}

func main() {
	// Sample data set
	items := []map[string]interface{}{
		{"name": "Alice", "age": 30},
		{"name": "Bob", "age": 25},
		{"name": "Charlie", "age": 35},
		{"name": "Diana", "age": 28},
	}

	// Example condition: keep items where item.age > 28
	conditionScript := "item.age > 28"

	filtered, err := FilterItems(conditionScript, items)
	if err != nil {
		log.Fatalf("FilterItems error: %v", err)
	}

	fmt.Println("Filtered items (age > 28):")
	for _, it := range filtered {
		fmt.Printf("%+v\n", it)
	}
}

